return [
  {
    json: {
      tier_id: 'ae',
      display_name: 'Account Executive',
      inbox_address: 'user@example.com',
      client_id: 'tier_ae',
      priority: 3,
      escalates_to: ''
    }
  },
  {
    json: {
      tier_id: 'bdr',
      display_name: 'BDR / SDR',
      inbox_address: 'user@example.com',
      client_id: 'tier_bdr',
      priority: 2,
      escalates_to: 'ae'
    }
  },
  {
    json: {
      tier_id: 'marketing',
      display_name: 'Marketing',
      inbox_address: 'user@example.com',
      client_id: 'tier_mkt',
      priority: 1,
      escalates_to: 'bdr'
    }
  }
];

const responses = $input.all();
const configRows = $('⚙️ Team_Config').all();
const report = [];
let totalBlocked = 0;

for (let i = 0; i < responses.length; i++) {
  const meta = configRows[i] ? configRows[i].json : {};
  const resp = responses[i].json;
  const entries = Array.isArray(resp.entries) ? resp.entries : Array.isArray(resp) ? resp : [];

  report.push({
    inbox_id: meta.inbox_address,
    tier_id: meta.tier_id,
    display_name: meta.display_name,
    priority: meta.priority,
    total_blocked: entries.length,
    blocked_prospects: entries.map(e => ({
      prospect: e.entry || 'unknown',
      reason: e.reason || 'No reason',
      blocked_at: e.created_at || 'unknown'
    }))
  });
  totalBlocked += entries.length;
}

report.sort((a, b) => (b.priority || 0) - (a.priority || 0));

return [{ json: {
  status: 'AUDIT_COMPLETE',
  total_inboxes: report.length,
  total_active_blocks: totalBlocked,
  report,
  generated_at: new Date().toISOString()
} }];

// ====================================================
// ⚙️ ONLY EDIT THIS — your n8n instance URL
// ====================================================

const n8n_url = 'https://stuctstunter.zeabur.app';

// ====================================================
// 🛑 DO NOT EDIT BELOW
// ====================================================

const rows = $input.all().map(i => i.json);

if (rows.length === 0) {
  throw new Error('Team_Config DataTable is empty. Run Layer 0A first.');
}

const config = { n8n_url };

for (const row of rows) {
  const tier = (row.tier_id || '').toLowerCase().trim();
  config[tier + '_inbox'] = row.inbox_address;
  config[tier + '_client_id'] = row.client_id;
  config[tier + '_display_name'] = row.display_name;
  config[tier + '_priority'] = row.priority;
  config[tier + '_escalates_to'] = row.escalates_to || '';
}

return [{ json: config }];

const removed = $input.all().map(i => i.json);

const byTier = {};
for (const item of removed) {
  const tier = item.tier_id || 'unknown';
  if (!byTier[tier]) byTier[tier] = { display_name: item.display_name, count: 0, prospects: [] };
  byTier[tier].count++;
  byTier[tier].prospects.push(item.prospect);
}

const summaryLines = Object.entries(byTier).map(([tier, data]) => 
  '- ' + data.display_name + ' (' + tier + '): ' + data.count + ' leads released'
);

return [{ json: {
  status: 'DECAY_COMPLETE',
  total_released: removed.length,
  by_tier: byTier,
  message: 'Decay Timer Complete. Released ' + removed.length + ' prospects back into the TAM.',
  summary: summaryLines.join('\n'),
  timestamp: new Date().toISOString()
} }];

// ====================================================
// ⚙️ PLAN TIER — only thing you edit here
// ====================================================

const plan_tier = 'free';
const TIER_LIMITS = { free: 3, pro: 50, enterprise: 500 };
const max_inboxes = TIER_LIMITS[plan_tier] || 3;

// ====================================================
// 🛑 DO NOT EDIT BELOW — reads from DataTable + API
// ====================================================

// Load Team_Config rows (already one item per row)
const configRows = $('⚙️ Load Team_Config').all().map(i => i.json);

if (configRows.length === 0) {
  throw new Error('Team_Config DataTable is empty. Add your inbox rows first.');
}

if (configRows.length > max_inboxes) {
  throw new Error('Team_Config has ' + configRows.length + ' inboxes but ' + plan_tier + ' plan allows ' + max_inboxes + '.');
}

// Build wanted list from DataTable
const wanted = configRows.map(row => {
  const addr = (row.inbox_address || '').toLowerCase().trim();
  const parts = addr.split('@');
  return {
    username: parts[0] || '',
    domain: parts[1] || 'agentmail.to',
    display_name: (row.display_name || '').trim(),
    client_id: (row.client_id || '').trim(),
    tier_id: (row.tier_id || '').trim(),
    priority: row.priority || 0,
    escalates_to: (row.escalates_to || '').trim(),
    expected_inbox_id: addr
  };
});

// Read live inboxes from API
const liveResponse = $input.first().json;
const liveInboxes = Array.isArray(liveResponse.inboxes) ? liveResponse.inboxes : Array.isArray(liveResponse) ? liveResponse : [];
const liveIds = new Set(liveInboxes.map(i => String(i.inbox_id || '').toLowerCase().trim()));
const wantedIds = new Set(wanted.map(w => w.expected_inbox_id));

const matched = [];
const missing = [];

for (const w of wanted) {
  if (liveIds.has(w.expected_inbox_id)) { matched.push(w); }
  else { missing.push(w); }
}

const orphaned = liveInboxes
  .filter(i => { const id = String(i.inbox_id || '').toLowerCase().trim(); return id && !wantedIds.has(id); })
  .map(i => ({ inbox_id: String(i.inbox_id).toLowerCase().trim(), display_name: i.display_name || null, client_id: i.client_id || null }));

const slots_used = liveInboxes.length;
const slots_available = Math.max(0, max_inboxes - slots_used);
const freed_if_cleaned = orphaned.length;
const slots_after_cleanup = Math.max(0, max_inboxes - (slots_used - freed_if_cleaned));
const can_create = missing.length <= slots_available;
const can_create_after_cleanup = missing.length <= slots_after_cleanup;

let action;
if (missing.length === 0) { action = 'ALL_MATCHED'; }
else if (can_create) { action = 'CREATE'; }
else { action = 'TIER_BLOCKED'; }

return [{ json: { plan: { tier: plan_tier, max_inboxes, slots_used, slots_available, freed_if_cleaned, slots_after_cleanup, can_create, can_create_after_cleanup }, action, wanted_count: wanted.length, live_count: liveInboxes.length, matched_count: matched.length, missing_count: missing.length, orphaned_count: orphaned.length, matched, missing, orphaned } }];

const compareResult = $('🔍 Compare + Tier Check').first().json;
const missing = compareResult.missing || [];
return missing.map(i => ({ json: i }));

const liveResponse = $input.first().json;
const liveInboxes = Array.isArray(liveResponse.inboxes) ? liveResponse.inboxes : Array.isArray(liveResponse) ? liveResponse : [];
const liveIds = new Set(liveInboxes.map(i => String(i.inbox_id || '').toLowerCase().trim()));

const compareResult = $('🔍 Compare + Tier Check').first().json;
const wanted = [...compareResult.matched, ...compareResult.missing];

const confirmed = [];
const still_failed = [];

for (const inbox of wanted) {
  if (liveIds.has(inbox.expected_inbox_id)) { confirmed.push(inbox.expected_inbox_id); }
  else { still_failed.push(inbox.expected_inbox_id); }
}

const allOk = still_failed.length === 0;

return [{ json: { status: allOk ? 'PROVISIONING_COMPLETE' : 'PROVISIONING_PARTIAL', plan: compareResult.plan, wanted: wanted.length, confirmed_live: confirmed.length, failed_count: still_failed.length, confirmed, still_failed, orphaned: compareResult.orphaned || [], orphaned_count: compareResult.orphaned_count || 0, next_step: allOk ? ((compareResult.orphaned_count || 0) > 0 ? 'All wanted inboxes live. Delete orphaned inboxes then run Layer 0B.' : 'All inboxes live. Run Layer 1 to register webhooks.') : 'Some inboxes failed. Check AgentMail credentials.', timestamp: new Date().toISOString() } }];

const data = $('🔍 Compare + Tier Check').first().json;
const plan = data.plan;
const missing = data.missing || [];
const orphaned = data.orphaned || [];
const orphanedIds = orphaned.map(o => o.inbox_id);

let resolution;
if (plan.can_create_after_cleanup) {
  resolution = { action_required: 'DELETE_ORPHANED_THEN_RETRY', instructions: ['1. Copy the orphaned inbox IDs below.', '2. Paste into ⚙️ Delete Config node.', '3. Run ▶️ Run Cleanup.', '4. Run ▶️ Run Provisioning again.'], inboxes_to_delete: orphanedIds, slots_freed: plan.freed_if_cleaned, will_succeed: plan.slots_after_cleanup >= missing.length };
} else {
  resolution = { action_required: 'UPGRADE_PLAN', instructions: ['Your ' + plan.tier + ' plan allows ' + plan.max_inboxes + ' inboxes.', 'You need ' + missing.length + ' new slots but only ' + plan.slots_after_cleanup + ' available after cleanup.', 'Upgrade your plan or reduce rows in Team_Config.'], will_succeed: false };
}

return [{ json: { status: 'TIER_BLOCKED', plan, missing: missing.map(m => m.expected_inbox_id), orphaned, resolution, timestamp: new Date().toISOString() } }];

// ============================================
// HIERARCHY ENFORCEMENT — Reads Team_Config
// ============================================
// $input = DataTable rows (config)
// Webhook payload = named reference to webhook node
// ============================================

// 1. Read config from DataTable (comes via $input)
const configRows = $input.all().map(i => i.json);

if (configRows.length === 0) {
  return [{ json: { action: 'SKIP', reason: 'Team_Config DataTable is empty.' } }];
}

// 2. Read webhook payload from the WEBHOOK NODE (not $input)
const webhookData = $('⚡ Webhook: message.sent').first().json;
const body = webhookData.body || webhookData;
const event = body.event_type ? body : (body.body || body);

if (!event.send || event.event_type !== 'message.sent') {
  return [{ json: { action: 'SKIP', reason: 'Not a message.sent event. Got: ' + (event.event_type || 'unknown'), debug_keys: Object.keys(event) } }];
}

// 3. Build teams lookup from DataTable
const teams = {};
for (const row of configRows) {
  teams[row.tier_id] = {
    inbox: (row.inbox_address || '').toLowerCase(),
    priority: row.priority || 0,
    display_name: row.display_name || row.tier_id
  };
}

// 4. Build inbox-to-tier lookup
const inboxToTier = {};
for (const [tierId, data] of Object.entries(teams)) {
  inboxToTier[data.inbox] = tierId;
}

// 5. Parse sender and recipients
const send = event.send;
const senderInbox = (send.inbox_id || '').toLowerCase();
const prospects = (send.recipients || []).map(r => r.toLowerCase().trim());

if (!senderInbox || prospects.length === 0) {
  return [{ json: { action: 'SKIP', reason: 'Missing inbox_id or recipients.', event_id: event.event_id } }];
}

const senderTierId = inboxToTier[senderInbox];
if (!senderTierId) {
  return [{ json: { action: 'SKIP', reason: 'Sender "' + send.inbox_id + '" not in Team_Config. Known inboxes: ' + Object.keys(inboxToTier).join(', '), event_id: event.event_id } }];
}

const senderPriority = teams[senderTierId].priority;

// 6. Find all tiers with lower priority
const lowerTiers = Object.entries(teams)
  .filter(([tid, data]) => data.priority < senderPriority)
  .map(([tid, data]) => ({ tier_id: tid, ...data }));

if (lowerTiers.length === 0) {
  return [{ json: { action: 'NONE', sender: send.inbox_id, sender_team: senderTierId, prospects, event_id: event.event_id, message: senderTierId.toUpperCase() + ' is lowest active tier. No blocks needed.' } }];
}

// 7. Generate block items
const blocks = [];
for (const prospect of prospects) {
  for (const lower of lowerTiers) {
    blocks.push({ json: {
      action: 'BLOCK',
      inbox_id: lower.inbox,
      blocked_team: lower.tier_id,
      prospect_email: prospect,
      sender_inbox: send.inbox_id,
      sender_team: senderTierId,
      thread_id: send.thread_id,
      message_id: send.message_id,
      event_id: event.event_id,
      reason: 'HIERARCHY_LOCK: ' + senderTierId.toUpperCase() + ' (' + send.inbox_id + ') engaged ' + prospect + '. ' + lower.tier_id.toUpperCase() + ' blocked. [event:' + event.event_id + ']'
    } });
  }
}

return blocks.length > 0 ? blocks : [{ json: { action: 'NONE', sender: send.inbox_id, sender_team: senderTierId, event_id: event.event_id, message: 'No blocks to execute.' } }];

const blocks = $input.all();
const calcItems = $('🧠 Calculate Hierarchy Blocks').all().filter(i => i.json.action === 'BLOCK');
const results = blocks.map((b, i) => {
  const meta = calcItems[i] ? calcItems[i].json : {};
  return { inbox_blocked: meta.inbox_id || 'unknown', team_blocked: meta.blocked_team || 'unknown', prospect: meta.prospect_email || 'unknown', success: b.json.scope_key || b.json.entry ? true : false };
});
const first = calcItems[0] ? calcItems[0].json : {};
return [{ json: { status: 'HIERARCHY_ENFORCED', trigger: 'message.sent webhook', sender: first.sender_inbox || 'unknown', sender_team: first.sender_team || 'unknown', event_id: first.event_id || 'unknown', blocks_executed: results.length, details: results, timestamp: new Date().toISOString() } }];

// Compare DataTable vs Live
const configRows = $('⚙️ Load Team_Config').all().map(i => i.json);
const live = $input.first().json;
const liveInboxes = Array.isArray(live.inboxes) ? live.inboxes : live;

const desired = new Set(configRows.map(r => (r.inbox_address || '').toLowerCase()));

const orphaned = liveInboxes
  .map(i => (i.inbox_id || '').toLowerCase())
  .filter(id => id && !desired.has(id));

if (orphaned.length === 0) {
  return [{ json: { action: 'NONE', message: 'No orphaned inboxes found.' } }];
}

return orphaned.map(id => ({
  json: {
    action: 'DELETE',
    inbox_id: id,
    url: 'https://api.agentmail.to/v0/inboxes/' + id
  }
}));

const deleted = $input.all().map(i => i.json.inbox_id);
return [{ json: {
  status: 'CLEANUP_COMPLETE',
  deleted_count: deleted.length,
  deleted,
  timestamp: new Date().toISOString()
} }];

// ============================================
// ENHANCED ROUTING — Labels + Shielding
// ============================================
const configRows = $input.all().map(i => i.json);
const webhookData = $('⚡ Webhook: message.received').first().json;

const msg = webhookData.body?.message || webhookData.message;
if (!msg || !msg.inbox_id) return [{ json: { action: 'SKIP', reason: 'Invalid payload' } }];

// 1. Identify Receiver
const receiver = configRows.find(c => c.inbox_address === msg.inbox_id);
if (!receiver) return [{ json: { action: 'SKIP', reason: 'Inbox not in Team_Config' } }];

// 2. Signal Check
const body = (msg.extracted_text || msg.text || "").toLowerCase();
let signal = 'NEUTRAL';
if (['interested', 'call', 'pricing', 'demo', 'schedule'].some(k => body.includes(k))) signal = 'HOT';
if (['stop', 'unsubscribe', 'remove'].some(k => body.includes(k))) signal = 'COLD';

// 3. Routing Decision
let action = 'PROCESS'; 
let label_to_add = `reply-${signal.toLowerCase()}`;
// Block the receiver (e.g., Marketing) from sending more automated emails unless the lead is cold (unsubscribe)
let block_needed = (signal !== 'COLD' && receiver.tier_id !== 'ae');

return [{
  json: {
    action,
    signal,
    label_to_add,
    block_needed,
    inbox_to_block: receiver.inbox_address,
    prospect: msg.from,
    thread_id: msg.thread_id,
    message_id: msg.message_id,
    receiving_tier: receiver.tier_id
  }
}];

const cfg = $('🔧 Build Config').first().json;
const liveWebhooks = $input.first().json.webhooks || [];

const workOrder = [];

const expectedHooks = [
  { url: cfg.n8n_url + '/webhook/agentmail-sent', event: 'message.sent' },
  { url: cfg.n8n_url + '/webhook/agentmail-received', event: 'message.received' }
];

for (const hook of expectedHooks) {
  const exists = liveWebhooks.some(w => w.url === hook.url && w.event_types && w.event_types.includes(hook.event));
  if (!exists) {
    workOrder.push({ action: 'CREATE_WEBHOOK', webhook_url: hook.url, event: hook.event });
  }
}

if (workOrder.length === 0) {
  return [{ json: { action: 'ALL_CLEAR', message: 'All webhooks registered.', config_summary: cfg, live_webhooks: liveWebhooks.map(w => ({ url: w.url, events: w.event_types })) } }];
}

return workOrder.map(task => ({ json: task }));

const responses = $input.all();
const configRows = $('⚙️ Read Team_Config').all();
const now = new Date();
const expired = [];

for (let i = 0; i < responses.length; i++) {
  const meta = configRows[i] ? configRows[i].json : {};
  const resp = responses[i].json;
  const entries = Array.isArray(resp.entries) ? resp.entries : Array.isArray(resp) ? resp : [];
  const decayDays = meta.decay_days || 30;

  for (const entry of entries) {
    if (!entry.created_at) continue;

    const blockDate = new Date(entry.created_at);
    const ageDays = (now - blockDate) / (1000 * 60 * 60 * 24);

    if (ageDays > decayDays) {
      expired.push({
        json: {
          action: 'DELETE',
          inbox_id: meta.inbox_address,
          tier_id: meta.tier_id,
          display_name: meta.display_name,
          prospect: entry.entry,
          age_days: Math.round(ageDays),
          decay_threshold: decayDays,
          url: 'https://api.agentmail.to/v0/inboxes/' + meta.inbox_address + '/lists/send/block/' + encodeURIComponent(entry.entry)
        }
      });
    }
  }
}

if (expired.length === 0) {
  return [{ json: { action: 'NONE', message: 'No expired blocks found. All entries within decay windows.' } }];
}

return expired;
